    let _antiAmplify = false;
    if (_recentLevel != null && histMean > 0 && _recentLevel >= 2 * histMean && _wRecentSku >= 0.5 && _biasSku > 1.0) {
      _biasSku = 1.0;
      _antiAmplify = true;
    }
    let _previsaoV2 = fc.previsao;
    let _capApplied = false;
    if (_recentLevel != null && (_wRecentSku > 0 || _biasSku !== 1.0)) {
      const blend = (1 - _wRecentSku) * fc.previsao + _wRecentSku * _recentLevel;
      _previsaoV2 = blend * _biasSku;
    }
    // Soft-cap de overshoot: limite físico contra previsões absurdas em SKUs
    // historicamente sobreestimados. Critério mais restritivo que antes para
    // não sufocar SKUs em crescimento real.
    if (_recentLevel != null && _overshootRate >= 0.75 && _previsaoV2 > 1.40 * _recentLevel) {
      _previsaoV2 = 1.25 * _recentLevel;
      _capApplied = true;
    }
    // === Inteligência data-driven multi-sinal ===
    // Três mecanismos combinados, todos derivados do próprio SKU:
    //
    //  1) REGIME DETECTION: detecta colapso/boom comparando a razão atual
    //     recentLevel/histTargetMean contra a distribuição de razões
    //     históricas (recent/forecastStat dos folds). Se a razão atual é
    //     outlier-baixa (Tukey), pull v2 em direção a recentLevel com peso
    //     proporcional à distância em IQRs.
    //
    //  2) RATIO FENCE: máximo plausível = recentLevel × maxRatio onde
    //     maxRatio é o maior actual/recentMean já observado nos folds (com
    //     20%% de folga). Se v2 ultrapassa, shrink logístico.
    //
    //  3) RECENT-WINDOW TUKEY FENCE: Q1/Q3/IQR sobre as ÚLTIMAS 12
    //     observações mensais (regime atual), não toda a história. SKUs em
    //     declínio têm fence apertado; SKUs estáveis têm fence largo.
    //
    // Cap superior final = min dos caps disponíveis. Cap inferior simétrico.
    const _q = (arr, p) => {
      const idx = (arr.length - 1) * p;
      const lo = Math.floor(idx), hi = Math.ceil(idx);
      return lo === hi ? arr[lo] : arr[lo] + (arr[hi] - arr[lo]) * (idx - lo);
    };
    // ---- Coleta observações DATADAS (ym, value), dedup, ordena desc ----
    const _tmMonth = tm.split('-')[1];
    const _obsMap = new Map();
    for (const yk of Object.keys(histData)) {
      for (const [mk, v] of Object.entries(histData[yk])) {
        if (typeof v === 'number' && !isNaN(v)) _obsMap.set(mk, v);
      }
    }
    for (let i = 0; i < years.length; i++) {
      if (typeof values[i] === 'number' && !isNaN(values[i])) {
        _obsMap.set(`${years[i]}-${_tmMonth}`, values[i]);
      }
    }
    for (const r of (w.recentMonths || [])) {
      if (typeof r.value === 'number' && !isNaN(r.value)) _obsMap.set(r.key, r.value);
    }
    const _obsSorted = [..._obsMap.entries()].sort((a, b) => b[0].localeCompare(a[0]));
    const _recentValues = _obsSorted.slice(0, 12).map((e) => e[1]).sort((a, b) => a - b);
    const _allValues = _obsSorted.map((e) => e[1]).sort((a, b) => a - b);
    // ---- (1) REGIME DETECTION via Tukey sobre razões históricas ----
    let _regimeShift = null;
    let _regimeRatio = null;
    const _histRatios = _histCtx
      .filter((c) => c.forecastStat > 0 && c.recent.length)
      .map((c) => (c.recent.reduce((a, b) => a + b, 0) / c.recent.length) / c.forecastStat);
    const _histTargetMean = values.length ? _mean(values) : null;
    if (_histRatios.length >= 2 && _recentLevel != null && _histTargetMean != null && _histTargetMean > 0) {
      const _rs = [..._histRatios].sort((a, b) => a - b);
      const currentRatio = _recentLevel / _histTargetMean;
      _regimeRatio = parseFloat(currentRatio.toFixed(3));
      // Sinal A — Tukey 1.5·IQR (estatística clássica). Funciona quando os
      // ratios históricos são razoavelmente simétricos.
      let _tukeyHit = null;
      if (_rs.length >= 3) {
        const rq1 = _q(_rs, 0.25);
        const rq3 = _q(_rs, 0.75);
        const riqr = rq3 - rq1;
        const rLower = rq1 - 1.5 * riqr;
        const rUpper = rq3 + 1.5 * riqr;
        if (riqr > 0 && currentRatio < rLower) {
          const breachIqr = (rLower - currentRatio) / riqr;
          _tukeyHit = { direction: 'collapse', fenceRatio: rLower, pullW: Math.min(0.8, breachIqr / (breachIqr + 1.0)) };
        } else if (riqr > 0 && currentRatio > rUpper) {
          const breachIqr = (currentRatio - rUpper) / riqr;
          _tukeyHit = { direction: 'boom', fenceRatio: rUpper, pullW: Math.min(0.5, breachIqr / (breachIqr + 1.5)) };
        }
      }
      // Sinal B — Empirical bounds. Se currentRatio está abaixo do MENOR
      // ratio jamais observado neste SKU (com folga 10%), é colapso fora
      // da experiência. Robusto a outliers altos que inflam o IQR Tukey.
      const minHist = _rs[0];
      const maxHist = _rs[_rs.length - 1];
      let _empHit = null;
      if (currentRatio < minHist * 0.9 && minHist > 0) {
        const breach = (minHist - currentRatio) / minHist;
        _empHit = { direction: 'collapse', fenceRatio: minHist, pullW: Math.min(0.6, Math.max(0.4, breach)) };
      } else if (currentRatio > maxHist * 1.1 && maxHist > 0) {
        const breach = (currentRatio - maxHist) / maxHist;
        _empHit = { direction: 'boom', fenceRatio: maxHist, pullW: Math.min(0.6, Math.max(0.3, breach * 0.5)) };
      }
      // Combinação: usa o sinal mais forte (maior pullW). Se ambos sinais
      // concordam, vence o de maior pull. Se discordam, empirical vence —
      // Tukey pode estar contaminado por outlier alto.
      const _hit = (_empHit && _tukeyHit)
        ? (_empHit.pullW >= _tukeyHit.pullW ? _empHit : _tukeyHit)
        : (_empHit || _tukeyHit);
      if (_hit) {
        _previsaoV2 = (1 - _hit.pullW) * _previsaoV2 + _hit.pullW * _recentLevel;
        // Piso anti-colapso-catastrófico: em collapse, não cair abaixo de
        // 50% da previsão estatística original (fc.previsao). Evita casos onde
        // pullW alto + recentLevel muito baixo levam v2 a praticamente zero
        // num SKU que de fato voltou a vender.
        if (_hit.direction === 'collapse' && _previsaoV2 < fc.previsao * 0.5) {
          _previsaoV2 = fc.previsao * 0.5;
        }
        _regimeShift = {
          direction: _hit.direction,
          currentRatio: _regimeRatio,
          fenceRatio: parseFloat(_hit.fenceRatio.toFixed(3)),
          pullWeight: parseFloat(_hit.pullW.toFixed(3)),
          source: _hit === _empHit ? 'empirical' : 'tukey',
        };
      }
    }
    // ---- (2) RATIO FENCE: cap = recentLevel × maxHistRatio × 1.2 ----
    let _ratioUpper = null, _ratioLower = null;
    const _actualRatios = _histCtx
      .filter((c) => c.recent.length && (c.recent.reduce((a, b) => a + b, 0) / c.recent.length) > 0)
      .map((c) => c.actual / (c.recent.reduce((a, b) => a + b, 0) / c.recent.length));
    if (_actualRatios.length >= 2 && _recentLevel != null && _recentLevel > 0) {
      const rmax = Math.max(..._actualRatios);
      const rmin = Math.min(..._actualRatios.filter((x) => x > 0));
      _ratioUpper = _recentLevel * rmax * 1.2;
      _ratioLower = isFinite(rmin) ? _recentLevel * rmin * 0.8 : null;
    }
    // ---- (3) RECENT-WINDOW TUKEY (últimas 12 obs) ----
    let _tukeyUpper = null, _tukeyLower = null, _tukeyMedian = null, _tukeyIqr = null;
    if (_recentValues.length >= 4) {
      const q1 = _q(_recentValues, 0.25);
      const q3 = _q(_recentValues, 0.75);
      _tukeyMedian = _q(_recentValues, 0.5);
      _tukeyIqr = q3 - q1;
      if (_tukeyIqr > 0) {
        _tukeyUpper = q3 + 1.5 * _tukeyIqr;
        _tukeyLower = Math.max(0, q1 - 1.5 * _tukeyIqr);
      }
    }
    // ---- Combinação: cap = min disponível (mais restritivo) ----
    const _upperCandidates = [_ratioUpper, _tukeyUpper].filter((x) => x != null && isFinite(x) && x > 0);
    const _lowerCandidates = [_ratioLower, _tukeyLower].filter((x) => x != null && isFinite(x) && x > 0);
    const _finalUpper = _upperCandidates.length ? Math.min(..._upperCandidates) : null;
    const _finalLower = _lowerCandidates.length ? Math.max(..._lowerCandidates) : null;
    let _fenceApplied = false;
    let _fenceInfo = null;
    if (_finalUpper != null && _previsaoV2 > _finalUpper) {
      const overshoot = _previsaoV2 / _finalUpper;
      const shrinkW = (overshoot - 1) / (overshoot - 1 + 0.5);
      _previsaoV2 = (1 - shrinkW) * _previsaoV2 + shrinkW * _finalUpper;
      _fenceApplied = true;
      _fenceInfo = {
        direction: 'down',
        fence: parseFloat(_finalUpper.toFixed(3)),
        ratioCap: _ratioUpper != null ? parseFloat(_ratioUpper.toFixed(3)) : null,
        tukeyCap: _tukeyUpper != null ? parseFloat(_tukeyUpper.toFixed(3)) : null,
        recentLevel: _recentLevel != null ? parseFloat(_recentLevel.toFixed(3)) : null,
        shrinkWeight: parseFloat(shrinkW.toFixed(3)),
      };
    } else if (_finalLower != null && _previsaoV2 < _finalLower && _previsaoV2 > 0) {
      const undershoot = _finalLower / _previsaoV2;
      const shrinkW = (undershoot - 1) / (undershoot - 1 + 0.5);
      _previsaoV2 = (1 - shrinkW) * _previsaoV2 + shrinkW * _finalLower;
      _fenceApplied = true;
      _fenceInfo = {
        direction: 'up',
        fence: parseFloat(_finalLower.toFixed(3)),
        ratioCap: _ratioLower != null ? parseFloat(_ratioLower.toFixed(3)) : null,
        tukeyCap: _tukeyLower != null ? parseFloat(_tukeyLower.toFixed(3)) : null,
        recentLevel: _recentLevel != null ? parseFloat(_recentLevel.toFixed(3)) : null,
        shrinkWeight: parseFloat(shrinkW.toFixed(3)),
      };
    }
    // === SELETOR LOO v1 vs v2 (do-no-harm SEM thresholds) ===
    // Em vez de "v2 só vence se for X% melhor" ou "reverte se moveu na
    // direção errada", deixamos o próprio histórico do SKU decidir via
    // leave-one-out cross-validation. Para cada fold k:
    //   - treina (w*, b*) nos folds ≠ k (mesma loss assimétrica)
    //   - prevê o fold k com v1 (forecastStat) e v2 ((1-w*)·fs + w*·rec)·b*
    //   - acumula erro asymétrico de cada um
    // Vencedor (menor erro acumulado) ganha o SKU. Sem thresholds.
    //
    // Se v1 vence, descarta tudo que v2 fez (calibração + soft-cap + regime
    // + fence) e devolve fc.previsao. Caso contrário mantém _previsaoV2.
    let _looErrV1 = null, _looErrV2 = null;
    let _selector = 'v2';
    if (_histCtx.length >= 3) {
      let eV1 = 0, eV2 = 0;
      for (let k = 0; k < _histCtx.length; k++) {
        const train = _histCtx.filter((_, i) => i !== k);
        const test = _histCtx[k];
        let bw = 0, bb = 1.0, be = Infinity;
        for (const wc of _wGrid) {
          for (const bc of _bGrid) {
            let s = 0;
            for (const ctx of train) {
              const rm = ctx.recent.length
                ? ctx.recent.reduce((a, b) => a + b, 0) / ctx.recent.length
                : ctx.forecastStat;
              const pr = ((1 - wc) * ctx.forecastStat + wc * rm) * bc;
              const d = ctx.actual - pr;
              s += d > 0 ? d * _UNDER_PENALTY : (-d) * _OVER_PENALTY;
            }
            if (s < be) { be = s; bw = wc; bb = bc; }
          }
        }
        const tRm = test.recent.length
          ? test.recent.reduce((a, b) => a + b, 0) / test.recent.length
          : test.forecastStat;
        const v1Pred = test.forecastStat;
        const v2Pred = ((1 - bw) * test.forecastStat + bw * tRm) * bb;
        const d1 = test.actual - v1Pred;
        const d2 = test.actual - v2Pred;
        eV1 += d1 > 0 ? d1 * _UNDER_PENALTY : (-d1) * _OVER_PENALTY;
        eV2 += d2 > 0 ? d2 * _UNDER_PENALTY : (-d2) * _OVER_PENALTY;
      }
      _looErrV1 = parseFloat(eV1.toFixed(3));
      _looErrV2 = parseFloat(eV2.toFixed(3));
      // v1 só vence se for ≥5% melhor (tie-break pró-v2).
      if (eV1 < eV2 * 0.95) _selector = 'v1';
    }
    // === INSTRUMENTAÇÃO (contrafactual sem viés de seleção) ===
    // Snapshot dos DOIS candidatos para os MESMOS SKU-mês, ANTES de o
    // seletor escolher. Não altera previsao escolhida — só registra.
    //   predV1     = v1 puro (forecastStat / ensemble base)
    //   predV2Full = pipeline v2 completo (calibração + soft-cap + regime +
    //                fence), ignorando a decisão do seletor.
    const _predV1 = parseFloat(Math.max(0, fc.previsao).toFixed(3));
    const _predV2Full = parseFloat(Math.max(0, _previsaoV2).toFixed(3));
    if (_selector === 'v1' && !_regimeShift) {
      // Descarta todo o pipeline v2 — o próprio SKU mostrou que v1 é melhor
      // historicamente E não há sinal de mudança de regime AGORA.
      _previsaoV2 = fc.previsao;
      _capApplied = false;
      _fenceApplied = false;
      _fenceInfo = null;
      // Momentum check: LOO julga só passado. Se o recente atual difere
      // muito de fc.previsao (>30%), aplica shrink leve em direção ao
      // recente — captura crescimento/queda que o histórico não viu.
      if (_recentLevel != null && fc.previsao > 0) {
        const ratio = _recentLevel / fc.previsao;
        if (ratio > 1.3 || (ratio < 0.7 && _recentLevel > 0)) {
          _previsaoV2 = 0.7 * fc.previsao + 0.3 * _recentLevel;
          _selector = 'v1+momentum';
        }
      }
    } else if (_selector === 'v1' && _regimeShift) {
      // V1 venceu o LOO, mas há mudança de regime detectada AGORA. O LOO
      // é cego pra isso porque só julga o passado: se o colapso/boom é
      // recente, nenhum fold antigo o captura. Aplica regime shift sobre
      // o v1 (em vez de descartar) — o sinal é estatístico (Tukey sobre
      // razões históricas), não arbitrário.
      const pullW = _regimeShift.pullWeight;
      _previsaoV2 = (1 - pullW) * fc.previsao + pullW * _recentLevel;
      // Mesmo piso anti-colapso-catastrófico aplicado no branch v2.
      if (_regimeShift.direction === 'collapse' && _previsaoV2 < fc.previsao * 0.5) {
        _previsaoV2 = fc.previsao * 0.5;
      }
      _capApplied = false;
      _fenceApplied = false;
      _fenceInfo = null;
      _selector = 'v1+regime';
    }
    _previsaoV2 = Math.max(0, parseFloat(_previsaoV2.toFixed(3)));
    previsoes.push({
      mes: tm, previsao: _previsaoV2, tolerancePct: tol,
      intervaloConfianca: {
        lower: parseFloat(Math.max(0, _previsaoV2 * (1 - tol / 100)).toFixed(3)),
        upper: parseFloat((_previsaoV2 * (1 + tol / 100)).toFixed(3)),
      },
      confianca: _confidenceLabel(stats.sampleSize || 0, cvFactor),
      tipo: isSgb ? 'sgb' : 'ensemble',
      metodos: fc.metodos, pesos: fc.pesos,
      damping: {
        wRecent: _wRecentSku,
        biasFactor: _biasSku,
        wRecentSamples: _histCtx.length,
        wBestErr: _wBestErr != null ? parseFloat(_wBestErr.toFixed(3)) : null,
        recentLevel: _recentLevel != null ? parseFloat(_recentLevel.toFixed(3)) : null,
        lastReal: _recentVals[0] != null ? _recentVals[0] : null,
        overshootRate: parseFloat(_overshootRate.toFixed(3)),
        capApplied: _capApplied,
        fenceApplied: _fenceApplied,
        fenceInfo: _fenceInfo,
        regimeShift: _regimeShift,
        regimeRatio: _regimeRatio,
        selector: _selector,
        looErrV1: _looErrV1,
        looErrV2: _looErrV2,
        predV1: _predV1,
        predV2Full: _predV2Full,
        empSamples: _allValues.length,
        recentSamples: _recentValues.length,
        calibrated: _wBest != null,
      },
    });
  }
  base.previsoes = previsoes;
  return base;
}

// ── n8n bridge ── (compatível com Predict v2 e Backtest v2)
const results = [];
let validation = null;
let forecastTargets = null;
let targetMonths = null;
let meta = { totalSkus: 0, skuOffset: 0, skuLimit: 0 };
for (const item of $input.all()) {
  const d = item.json;
  const skus = Array.isArray(d.analysis) ? d.analysis : [d];
  if (!validation && d.validation) validation = d.validation;
  if (!forecastTargets && d.forecastTargets) forecastTargets = d.forecastTargets;
  if (!targetMonths && d.targetMonths) targetMonths = d.targetMonths;
  for (const k of ['totalSkus', 'skuOffset', 'skuLimit']) {
    if (k in d) meta[k] = d[k];
  }
  for (const sku of skus) {
    const row = seasonalForecast(sku);
    if (sku.backtestTarget != null) row.backtestTarget = sku.backtestTarget;
    if ('realValue' in sku) row.realValue = sku.realValue;
    if (validation != null) row._validation = validation;
    if (forecastTargets != null) row._forecastTargets = forecastTargets;
    if (targetMonths != null) row._targetMonths = targetMonths;
    row._meta = meta;
    results.push({ json: row });
  }
}
return results;

// Parse Result — inline. Achata para o formato que o front consome.
const results = [];
let validation = null, forecastTargets = null;
let meta = { totalSkus: 0, skuOffset: 0, skuLimit: 0 };

for (const item of $input.all()) {
  const data = item.json || {};
  if (!validation && data._validation) validation = data._validation;
  if (!forecastTargets && data._forecastTargets) forecastTargets = data._forecastTargets;
  if (data._meta) meta = data._meta;
  if (data.__metaOnly) continue;

  const row = {
    SKU: data.SKU,
    'Descrição': data['Descrição'],
    Formato: data.Formato || '',
    insufficientHistory: !!data.insufficientHistory,
    historyMonthsAvailable: data.historyMonthsAvailable || 0,
    monthsMissingForMin: data.monthsMissingForMin || 0,
    detalhes: {},
  };
  for (const prev of data.previsoes || []) {
    row[prev.mes] = prev.previsao;
    row.detalhes[prev.mes] = {
      previsao: prev.previsao,
      tolerancePct: prev.tolerancePct,
      intervaloConfianca: prev.intervaloConfianca,
      confianca: prev.confianca,
      tipo: prev.tipo,
      motivo: prev.motivo || null,
      damping: prev.damping || null,
    };
  }
  results.push(row);
}

const processedSkus = results.length;
const totalSkus = meta.totalSkus || 0;
const skuOffset = meta.skuOffset || 0;
const skuLimit = meta.skuLimit || 0;
const nextOffset = skuOffset + (skuLimit > 0 ? skuLimit : processedSkus);
const hasMore = totalSkus > 0 && nextOffset < totalSkus;

return [{ json: { data: results, validation, forecastTargets, totalSkus, processedSkus, skuOffset, skuLimit, nextOffset, hasMore } }];

// Combina o slice processado inline no acumulador.
// Lê o resultado direto de 'Inline Parse Result'.
const parsed = $('Inline Parse Result').all();
const predictResult = (parsed[0] && parsed[0].json) || {};
const aggRaw = $json.agg;
let current;
try {
  if (typeof aggRaw === 'string') current = JSON.parse(aggRaw);
  else if (Array.isArray(aggRaw)) current = aggRaw;
  else current = [];
  if (!Array.isArray(current)) current = [];
} catch (e) { current = []; }
const sliceData = Array.isArray(predictResult.data) ? predictResult.data : [];
const combined = current.concat(sliceData);

const validation = predictResult.validation || null;
const forecastTargets = predictResult.forecastTargets || null;

return [{
  json: {
    aggregate: JSON.stringify(combined),
    validationStr: validation != null ? JSON.stringify(validation) : 'null',
    targetsStr: forecastTargets != null ? JSON.stringify(forecastTargets) : 'null',
    meta: {
      totalSkus: predictResult.totalSkus || 0,
      processedSkus: predictResult.processedSkus || 0,
      processedSkusInSlice: sliceData.length,
      currentBeforeMerge: current.length,
      firstSliceSku: sliceData.length ? (sliceData[0].SKU || null) : null,
      aggRawType: typeof aggRaw,
      aggRawLen: typeof aggRaw === 'string' ? aggRaw.length : null,
      skuOffset: predictResult.skuOffset || 0,
      skuLimit: predictResult.skuLimit || 0,
      nextOffset: predictResult.nextOffset || 0,
      hasMore: !!predictResult.hasMore,
      aggregatedTotal: combined.length,
    },
  },
}];

// Monta o envelope final equivalente ao Save Response da v1.
// IMPORTANTE: o nó Redis 'get' substitui o $json a cada chamada encadeada,
// então lemos cada valor explicitamente do nó de origem.
function readFromNode(nodeName, prop) {
  try {
    const items = $(nodeName).all();
    if (!items || !items.length) return null;
    const v = items[0].json ? items[0].json[prop] : undefined;
    return v == null ? null : v;
  } catch (e) { return null; }
}

const aggRaw = readFromNode('Redis GET aggregate (finalize)', 'agg');
const validationRaw = readFromNode('Redis GET validation', 'validation');
const targetsRaw = readFromNode('Redis GET targets', 'targets');

let data = [];
try {
  if (typeof aggRaw === 'string') data = JSON.parse(aggRaw || '[]');
  else if (Array.isArray(aggRaw)) data = aggRaw;
} catch (e) { data = []; }
if (!Array.isArray(data)) data = [];

let validation = null;
try {
  if (typeof validationRaw === 'string') validation = JSON.parse(validationRaw);
  else if (validationRaw && typeof validationRaw === 'object') validation = validationRaw;
} catch (e) { validation = null; }

let forecastTargets = null;
try {
  if (typeof targetsRaw === 'string') forecastTargets = JSON.parse(targetsRaw);
  else if (Array.isArray(targetsRaw)) forecastTargets = targetsRaw;
} catch (e) { forecastTargets = null; }

const envelope = {
  data,
  createdAt: new Date().toISOString(),
  validation,
  forecastTargets,
};

return [{ json: { envelopeStr: JSON.stringify(envelope), count: data.length, debug: { aggRawType: typeof aggRaw, aggRawLen: typeof aggRaw === 'string' ? aggRaw.length : null, hasValidation: validation != null, hasTargets: forecastTargets != null } } }];
